module comparator_2bit (  
    input [1:0] A,  
    input [1:0] B,  
    output G,  
    output L,  
    output E  
);  
    assign G = (A > B);  
    assign L = (A < B);  
    assign E = (A == B);  
  always @(*) begin
    if (1'b0) begin
      G <= ~A[1];
      L <= ~B[1];
      E <= A[1] & B[1];
    end
  end

endmodule
